if($path==='/events/new'){require_permission('events.edit');if($method==='POST'){verify_csrf();$eventType=(string)post('event_type');if(!in_array($eventType,option_codes('event_type'),true)){flash('error','Choose a valid event type.');redirect('/events/new');}$slides=null;$original=null;if(isset($_FILES['slides'])&&$_FILES['slides']['error']!==UPLOAD_ERR_NO_FILE){$f=$_FILES['slides'];$allowed=['application/pdf'=>'pdf','application/vnd.ms-powerpoint'=>'ppt','application/vnd.openxmlformats-officedocument.presentationml.presentation'=>'pptx'];$mime=(new finfo(FILEINFO_MIME_TYPE))->file($f['tmp_name']);if($f['error']!==UPLOAD_ERR_OK||$f['size']>config('upload_max')||!isset($allowed[$mime])){flash('error','Slides must be a PDF, PPT, or PPTX within the upload limit.');redirect('/events/new');}$slides=bin2hex(random_bytes(20)).'.'.$allowed[$mime];$dest=dirname(__DIR__).'/storage/uploads/'.$slides;if(!move_uploaded_file($f['tmp_name'],$dest))throw new RuntimeException('Upload failed');$original=basename($f['name']);}db()->prepare('INSERT INTO events(title,event_type,starts_at,presentation_title,abstract,booking_url,conference_url,venue_address,slides_path,slides_original_name,created_by) VALUES(?,?,?,?,?,?,?,?,?,?,?)')->execute([trim(post('title')),$eventType,post('starts_at'),trim(post('presentation_title'))?:null,trim(post('abstract')),trim(post('booking_url'))?:null,trim(post('conference_url'))?:null,trim(post('venue_address'))?:null,$slides,$original,user()['id']]);$id=(int)db()->lastInsertId();audit('create','event',$id);redirect('/events/'.$id);}layout('New event',function(){?><h1>New event</h1><form class="card" method="post" enctype="multipart/form-data"><input type="hidden" name="_csrf" value="<?=csrf()?>"><div class="form-grid"><label>Event name<input name="title" required></label><label>Type<select name="event_type"><?php foreach(list_options('event_type') as $o):?><option value="<?=e($o['code'])?>"><?=e($o['label'])?></option><?php endforeach?></select></label><label>Date and time<input type="datetime-local" name="starts_at" required></label><label>Slides (PDF, PPT, PPTX)<input type="file" name="slides" accept=".pdf,.ppt,.pptx"></label><label id="presentation-field" style="display:none">Presentation title<input name="presentation_title"></label><label id="booking-field">Webinar booking URL<input type="url" name="booking_url" placeholder="https://..."></label><label id="conference-url-field" style="display:none">Conference URL<input type="url" name="conference_url" placeholder="https://..."></label><label id="venue-field" style="display:none">Conference address<textarea name="venue_address" rows="3"></textarea></label><label class="full">Abstract<textarea name="abstract" rows="7"></textarea></label></div><button>Save event</button></form><script>const type=document.querySelector("[name=event_type]"),booking=document.querySelector("#booking-field"),venue=document.querySelector("#venue-field"),conferenceUrl=document.querySelector("#conference-url-field"),presentation=document.querySelector("#presentation-field");function eventFields(){booking.style.display=type.value==="webinar"?"block":"none";venue.style.display=type.value==="conference"?"block":"none";conferenceUrl.style.display=type.value==="conference"?"block":"none";presentation.style.display=["conference","presentation"].includes(type.value)?"block":"none"}type.addEventListener("change",eventFields);eventFields()</script><?php });exit;}

if(preg_match('#^/events/(\d+)$#',$path,$m)){require_permission('events.view');$id=(int)$m[1];$s=db()->prepare('SELECT * FROM events WHERE id=?');$s->execute([$id]);$event=$s->fetch();if(!$event){http_response_code(404);exit('Event not found');}$s=db()->prepare('SELECT c.* FROM contacts c JOIN event_attendees ea ON ea.contact_id=c.id WHERE ea.event_id=? AND ea.attended=1 ORDER BY c.last_name');$s->execute([$id]);$attendees=array_values(array_filter($s->fetchAll(),fn($c)=>contact_access((int)$c['id'])!=='hidden'));$reminders=db()->prepare('SELECT * FROM event_reminders WHERE event_id=? AND user_id=? AND completed_at IS NULL ORDER BY due_at');$reminders->execute([$id,user()['id']]);layout($event['title'],function()use($event,$attendees,$id,$reminders){?><h1><?=e($event['title'])?></h1><div class="card"><p><strong><?=e(option_label('event_type',$event['event_type']))?></strong> Â· <?=e($event['starts_at'])?></p><?php if($event['presentation_title']):?><h2><?=e($event['presentation_title'])?></h2><?php endif?><?php if($event['booking_url']):?><p><strong>Booking link:</strong> <a href="<?=e($event['booking_url'])?>" target="_blank" rel="noopener"><?=e($event['booking_url'])?></a></p><?php endif?><?php if($event['conference_url']):?><p><strong>Conference website:</strong> <a href="<?=e($event['conference_url'])?>" target="_blank" rel="noopener"><?=e($event['conference_url'])?></a></p><?php endif?><?php if($event['venue_address']):?><p><strong>Conference address:</strong><br><?=nl2br(e($event['venue_address']))?></p><?php endif?><p><?=nl2br(e($event['abstract']))?></p><?php if($event['slides_path']):?><a class="btn secondary" href="/events/<?=$id?>/slides">View slides</a><?php endif?></div><div class="card"><h2>Attendees (<?=count($attendees)?>)</h2><table><?php foreach($attendees as $c):?><tr><td><a href="/contacts/<?=$c['id']?>"><?=e($c['first_name'].' '.$c['last_name'])?></a></td><td><?=e($c['company'])?></td></tr><?php endforeach?></table><?php if(can('events.edit')):?><form method="post" action="/events/<?=$id?>/attendees"><input type="hidden" name="_csrf" value="<?=csrf()?>"><label>Add contact<select name="contact_id" required><option value="">Choose contact</option><?php foreach(db()->query('SELECT id,first_name,last_name,company FROM contacts ORDER BY last_name')->fetchAll() as $c)if(contact_access((int)$c['id'])!=='hidden'):?><option value="<?=$c['id']?>"><?=e($c['last_name'].', '.$c['first_name'].' â€” '.$c['company'])?></option><?php endif?></select></label><button>Add attendee</button></form><hr><h3>Import attendees</h3><p class="muted">Upload XLSX, CSV, or TSV with First Name, Last Name, Email, Company, and Phone headers. Email is used to match existing contacts.</p><form method="post" action="/events/<?=$id?>/import" enctype="multipart/form-data"><input type="hidden" name="_csrf" value="<?=csrf()?>"><label>Attendee file<input type="file" name="attendees" accept=".xlsx,.csv,.tsv" required></label><button>Import attendees</button></form><?php endif?></div><div class="card"><h2>Event alerts</h2><p class="muted">Track calls for presentations, abstract deadlines, speaker follow-ups, or any other conference milestone.</p><?php foreach($reminders as $r):?><div class="note"><strong><?=e($r['message'])?></strong><div class="muted">Due <?=e($r['due_at'])?></div></div><?php endforeach?><form method="post" action="/events/<?=$id?>/reminders"><input type="hidden" name="_csrf" value="<?=csrf()?>"><div class="form-grid"><label>Alert message<input name="message" placeholder="Call for presentations opens" required></label><label>Target date and time<input type="datetime-local" name="due_at" required></label></div><button>Create event alert</button></form></div><?php });exit;}
