if($path==='/api/report'){require_permission('reports.view');$group=$_GET['group_by']??'tag';$allowed=['tag','company','score','event'];if(!in_array($group,$allowed,true))$group='tag';$params=[];$where=[visible_contact_sql('c')];if(!empty($_GET['name'])){$where[]="CONCAT(c.first_name,' ',c.last_name) LIKE ?";$params[]='%'.$_GET['name'].'%';}if(!empty($_GET['company'])){$where[]='c.company LIKE ?';$params[]='%'.$_GET['company'].'%';}if(!empty($_GET['tag'])){$where[]='ct.tag_id=?';$params[]=(int)$_GET['tag'];}$older=max(0,min(3650,(int)($_GET['updated_older_days']??0)));if($older)$where[]="c.updated_at < DATE_SUB(NOW(),INTERVAL $older DAY)";$within=max(0,min(3650,(int)($_GET['updated_within_days']??0)));if($within)$where[]="c.updated_at >= DATE_SUB(NOW(),INTERVAL $within DAY)";$created=max(0,min(3650,(int)($_GET['created_within_days']??0)));if($created)$where[]="c.created_at >= DATE_SUB(NOW(),INTERVAL $created DAY)";$emailStatus=$_GET['email_status']??'';if($emailStatus==='missing')$where[]="(c.email IS NULL OR c.email='')";elseif($emailStatus==='present')$where[]="c.email IS NOT NULL AND c.email<>''";$oppStatus=$_GET['opportunity_status']??'';if(in_array($oppStatus,option_codes('opportunity_status'),true)){$where[]='EXISTS(SELECT 1 FROM opportunities fo WHERE fo.contact_id=c.id AND fo.status=?)';$params[]=$oppStatus;}$w=$where?' WHERE '.implode(' AND ',$where):'';
 $queries=['tag'=>"SELECT t.name label,COUNT(DISTINCT c.id) value FROM contacts c JOIN contact_tags ct ON ct.contact_id=c.id JOIN tags t ON t.id=ct.tag_id $w GROUP BY t.id,t.name ORDER BY value DESC",'company'=>"SELECT COALESCE(NULLIF(c.company,''),'No company') label,COUNT(DISTINCT c.id) value FROM contacts c LEFT JOIN contact_tags ct ON ct.contact_id=c.id $w GROUP BY c.company ORDER BY value DESC LIMIT 30",'score'=>"SELECT o.score label,COUNT(DISTINCT o.id) value FROM opportunities o JOIN contacts c ON c.id=o.contact_id LEFT JOIN contact_tags ct ON ct.contact_id=c.id $w GROUP BY o.score",'event'=>"SELECT e.title label,COUNT(DISTINCT ea.contact_id) value FROM events e LEFT JOIN event_attendees ea ON ea.event_id=e.id LEFT JOIN contacts c ON c.id=ea.contact_id LEFT JOIN contact_tags ct ON ct.contact_id=c.id $w GROUP BY e.id,e.title ORDER BY value DESC"];$s=db()->prepare($queries[$group]);$s->execute($params);$rows=$s->fetchAll();if($group==='score')foreach($rows as &$row)$row['label']=option_label('opportunity_score',$row['label']);unset($row);header('Content-Type: application/json');echo json_encode(['labels'=>array_column($rows,'label'),'values'=>array_map('intval',array_column($rows,'value'))]);exit;}

if($path==='/reports'){require_permission('reports.view');if($method==='POST'){require_permission('reports.edit');verify_csrf();db()->prepare('INSERT INTO saved_reports(user_id,name,chart_type,group_by,filters_json,shared) VALUES(?,?,?,?,?,?)')->execute([user()['id'],trim(post('name')),post('chart_type'),post('group_by'),json_encode(['name'=>trim(post('filter_name')),'company'=>trim(post('company')),'tag'=>(int)post('tag'),'updated_older_days'=>(int)post('updated_older_days'),'updated_within_days'=>(int)post('updated_within_days'),'created_within_days'=>(int)post('created_within_days'),'email_status'=>post('email_status'),'opportunity_status'=>post('opportunity_status')]),post('shared')?1:0]);flash('success','Report saved.');redirect('/reports');}$s=db()->prepare('SELECT sr.*,u.username FROM saved_reports sr JOIN users u ON u.id=sr.user_id WHERE sr.user_id=? OR sr.shared=1 ORDER BY sr.created_at DESC');$s->execute([user()['id']]);$saved=$s->fetchAll();layout('Reports',function()use($saved){?><h1>Report builder</h1><div class="grid"><form class="card" id="report-form" method="post"><input type="hidden" name="_csrf" value="<?=csrf()?>"><label>Report name<input name="name" value="Contact report" required></label><div class="form-grid"><label>Group by<select name="group_by"><option value="tag">Tag</option><option value="company">Company</option><option value="score">Opportunity score</option><option value="event">Event</option></select></label><label>Chart<select name="chart_type"><option value="bar">Bar</option><option value="pie">Pie</option><option value="doughnut">Doughnut</option></select></label><label>Name contains<input name="filter_name"></label><label>Company contains<input name="company"></label><label>Tag<select name="tag"><option value="">Any</option><?php foreach(all_tags() as $t)if(tag_access((int)$t['id'])!=='hidden'):?><option value="<?=$t['id']?>"><?=e($t['name'])?></option><?php endif?></select></label><label>Not updated in more than (days)<input type="number" min="0" name="updated_older_days" placeholder="30"></label><label>Updated within (days)<input type="number" min="0" name="updated_within_days"></label><label>Created within (days)<input type="number" min="0" name="created_within_days"></label><label>Email<select name="email_status"><option value="">Any</option><option value="present">Has email</option><option value="missing">Missing email</option></select></label><label>Opportunity status<select name="opportunity_status"><option value="">Any</option><?php foreach(list_options('opportunity_status') as $o):?><option value="<?=e($o['code'])?>"><?=e($o['label'])?></option><?php endforeach?></select></label></div><div class="actions"><button type="button" id="run">Run report</button><?php if(can('reports.edit')):?><button class="secondary">Save report</button><label style="margin:0"><input style="width:auto" type="checkbox" name="shared" value="1"> Share</label><?php endif?></div></form><div class="card"><div class="chart-wrap"><canvas id="chart"></canvas></div></div></div><div class="card"><h2>Saved reports</h2><table><?php foreach($saved as $r):?><tr><td><?=e($r['name'])?></td><td><?=e($r['group_by'])?> / <?=e($r['chart_type'])?></td><td><?=e($r['username'])?><?=$r['shared']?' Â· shared':''?></td><td><button type="button" class="load" data-report='<?=e(json_encode($r))?>'>Load</button></td></tr><?php endforeach?></table></div><script src="https://cdn.jsdelivr.net/npm/chart.js@4.4.7/dist/chart.umd.min.js"></script><script>let chart;const f=document.querySelector('#report-form');async function run(){const p=new URLSearchParams({group_by:f.group_by.value,name:f.filter_name.value,company:f.company.value,tag:f.tag.value,updated_older_days:f.updated_older_days.value,updated_within_days:f.updated_within_days.value,created_within_days:f.created_within_days.value,email_status:f.email_status.value,opportunity_status:f.opportunity_status.value});const d=await fetch('/api/report?'+p).then(r=>r.json());chart?.destroy();chart=new Chart(document.querySelector('#chart'),{type:f.chart_type.value,data:{labels:d.labels,datasets:[{label:'Contacts',data:d.values,backgroundColor:['#1565c0','#43a047','#f9a825','#8e24aa','#e53935','#00838f']}]},options:{responsive:true,maintainAspectRatio:false}})}document.querySelector('#run').onclick=run;document.querySelectorAll('.load').forEach(b=>b.onclick=()=>{const r=JSON.parse(b.dataset.report),x=JSON.parse(r.filters_json);f.name.value=r.name;f.group_by.value=r.group_by;f.chart_type.value=r.chart_type;f.filter_name.value=x.name||'';f.company.value=x.company||'';f.tag.value=x.tag||'';f.updated_older_days.value=x.updated_older_days||'';f.updated_within_days.value=x.updated_within_days||'';f.created_within_days.value=x.created_within_days||'';f.email_status.value=x.email_status||'';f.opportunity_status.value=x.opportunity_status||'';run()});run()</script><?php });exit;}

if($path==='/admin/users'){if(!user()['is_admin']){http_response_code(403);exit('Forbidden');}if($method==='POST'){verify_csrf();$action=post('action');if($action==='user'){db()->prepare('INSERT INTO users(role_id,username,email,password_hash,force_password_change) VALUES(?,?,?,?,1)')->execute([(int)post('role_id')?:null,trim(post('username')),trim(post('email'))?:null,password_hash((string)post('password'),PASSWORD_DEFAULT)]);audit('create','user',(int)db()->lastInsertId());}elseif($action==='tag'){db()->prepare('INSERT INTO tags(name,color) VALUES(?,?)')->execute([trim(post('name')),post('color')]);audit('create','tag',(int)db()->lastInsertId());}elseif($action==='role'){db()->prepare('INSERT INTO roles(name,permissions_json) VALUES(?,?)')->execute([trim(post('name')),json_encode((array)post('permissions',[]))]);audit('create','role',(int)db()->lastInsertId());}elseif($action==='tag_permission'){db()->prepare('INSERT INTO tag_permissions(role_id,tag_id,access_level) VALUES(?,?,?) ON DUPLICATE KEY UPDATE access_level=VALUES(access_level)')->execute([(int)post('role_id'),(int)post('tag_id'),post('access_level')]);audit('update','tag_permission');}elseif($action==='reset'){db()->prepare('UPDATE users SET password_hash=?,force_password_change=1 WHERE id=?')->execute([password_hash((string)post('password'),PASSWORD_DEFAULT),(int)post('user_id')]);audit('password_reset','user',(int)post('user_id'));}flash('success','Admin change saved.');redirect('/admin/users');}$users=db()->query('SELECT u.*,r.name role_name FROM users u LEFT JOIN roles r ON r.id=u.role_id ORDER BY username')->fetchAll();$roles=db()->query('SELECT * FROM roles ORDER BY name')->fetchAll();$tags=all_tags();layout('Administration',function()use($users,$roles,$tags){$perms=['contacts.view','contacts.edit','events.view','events.edit','reports.view','reports.edit'];?><h1>Administration</h1><div class="grid"><form class="card" method="post"><h2>Create user</h2><input type="hidden" name="_csrf" value="<?=csrf()?>"><input type="hidden" name="action" value="user"><label>Username<input name="username" required></label><label>Email<input type="email" name="email"></label><label>Temporary password<input type="password" name="password" minlength="12" required></label><label>Role<select name="role_id"><?php foreach($roles as $r):?><option value="<?=$r['id']?>"><?=e($r['name'])?></option><?php endforeach?></select></label><button>Create user</button></form><form class="card" method="post"><h2>Create role</h2><input type="hidden" name="_csrf" value="<?=csrf()?>"><input type="hidden" name="action" value="role"><label>Name<input name="name" required></label><div class="checkboxes"><?php foreach($perms as $p):?><label><input type="checkbox" name="permissions[]" value="<?=$p?>"><?=$p?></label><?php endforeach?></div><br><button>Create role</button></form><form class="card" method="post"><h2>Create tag</h2><input type="hidden" name="_csrf" value="<?=csrf()?>"><input type="hidden" name="action" value="tag"><label>Name<input name="name" required></label><label>Color<input type="color" name="color" value="#1565c0"></label><button>Create tag</button></form><form class="card" method="post"><h2>Tag security</h2><input type="hidden" name="_csrf" value="<?=csrf()?>"><input type="hidden" name="action" value="tag_permission"><label>Role<select name="role_id"><?php foreach($roles as $r):?><option value="<?=$r['id']?>"><?=e($r['name'])?></option><?php endforeach?></select></label><label>Tag<select name="tag_id"><?php foreach($tags as $t):?><option value="<?=$t['id']?>"><?=e($t['name'])?></option><?php endforeach?></select></label><label>Access<select name="access_level"><option value="hidden">Hidden</option><option value="read">Read only</option><option value="write">Write</option></select></label><button>Apply security</button></form></div><div class="card"><h2>Users</h2><table><thead><tr><th>User</th><th>Role</th><th>Status</th><th>Reset password</th></tr></thead><?php foreach($users as $u):?><tr><td><?=e($u['username'])?><br><span class="muted"><?=e($u['email'])?></span></td><td><?=$u['is_admin']?'Central admin':e($u['role_name'])?></td><td><?=$u['active']?'Active':'Disabled'?></td><td><form method="post" class="actions"><input type="hidden" name="_csrf" value="<?=csrf()?>"><input type="hidden" name="action" value="reset"><input type="hidden" name="user_id" value="<?=$u['id']?>"><input style="max-width:240px" type="password" name="password" minlength="12" placeholder="Temporary password" required><button>Reset</button></form></td></tr><?php endforeach?></table></div><?php });exit;}

